const hmacResult = $json;
if (!hmacResult.valid) {
  throw new Error('HMAC invalido: assinatura recusada pelo backend');
}
const webhookData = $('Webhook Trigger').item.json.body || $('Webhook Trigger').item.json;
const normalized_text = webhookData.normalized_text || '';
const provider_chain = webhookData.provider_chain || [];
const ingestion_id = webhookData.ingestion_id || '';
const shared_context = webhookData.shared_context || {};
  const systemPrompt = webhookData.systemPrompt || '';
  if (!systemPrompt) {
    throw new Error('PROMPT_AUSENTE: systemPrompt nao fornecido pelo Conferente.');
  }
if (!normalized_text) {
  throw new Error('Campo normalized_text ausente no payload');
}
if (!provider_chain || provider_chain.length === 0) {
  throw new Error('Campo provider_chain ausente ou vazio no payload');
}
return [{ json: { normalized_text, provider_chain, ingestion_id, shared_context, systemPrompt, hmac_valid: true } }];

const data = $json;
const provider = data.provider_chain[0];
const providerName = (provider.provider || 'openai').toLowerCase();
const apiKey = provider.api_key || '';

const systemPrompt = 'Você é o Gerente de Projetos (GP) — primeira persona técnica do Gatekeeper.\n\nSeu papel é validar:\n1. **Escopo**: Requisitos funcionais estão completos e testáveis?\n2. **Viabilidade**: É possível entregar com recursos e timeline planejados?\n3. **Stakeholders**: Estão todos identificados? Há consenso?\n4. **ROI**: O projeto agrega valor? Há riscos de negócio documentados?\n\nSEUS 6 OUTPUTS OBRIGATÓRIOS (em UMA resposta JSON):\n\n1. SCORES (0–100)\n   - escopo: clareza e completude de requisitos\n   - stack: alinhamento com capacidade da equipe\n   - dados: modelo de dados faz sentido para os fluxos?\n   - implementacao: timeline é realista?\n   - testes: estratégia de aceite definida?\n\n2. APPROVED (bool)\n   - true se pode proceder (escopo claro, stakeholders alinhados)\n   - false se há blocker de negócio\n\n3. ISSUES (array)\n   - Ambiguidades no escopo\n   - Requisitos conflitantes\n   - Stakeholders faltando\n   - Timeline não realista\n   - Riscos não documentados\n\n4. QUESTIONS (array)\n   - Perguntas que PRECISAM de resposta humana para proceder\n\n5. JUSTIFICATION (texto)\n   - Raciocínio resumido para aprovação/reprovação\n\n6. METADATA\n   - tentative: true em passada 1, false em passada 2\n\nSem improviso. Se não houver insumo suficiente, declare incerteza explícita.\n\nRETORNE APENAS JSON VÁLIDO (sem markdown, sem ```).';
const userMessage = JSON.stringify({ passada: 1, normalized_text: data.normalized_text, shared_context: data.shared_context });

let llmUrl, requestHeaders, requestBody;

if (providerName === 'anthropic') {
  llmUrl = 'https://api.anthropic.com/v1/messages';
  requestHeaders = {
    'Authorization': `Bearer ${apiKey}`,
    'anthropic-version': '2023-06-01',
    'Content-Type': 'application/json'
  };
  requestBody = {
    model: provider.model,
    max_tokens: 4000,
    temperature: 0.2,
    system: systemPrompt,
    messages: [{ role: 'user', content: userMessage }]
  };
} else if (providerName === 'openai') {
  llmUrl = 'https://api.openai.com/v1/chat/completions';
  requestHeaders = {
    'Authorization': `Bearer ${apiKey}`,
    'Content-Type': 'application/json'
  };
  requestBody = {
    model: provider.model,
    max_tokens: 4000,
    temperature: 0.2,
    messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userMessage }]
  };
} else if (providerName === 'deepseek') {
  llmUrl = 'https://api.deepseek.com/chat/completions';
  requestHeaders = {
    'Authorization': `Bearer ${apiKey}`,
    'Content-Type': 'application/json'
  };
  requestBody = {
    model: provider.model,
    max_tokens: 4000,
    temperature: 0.2,
    messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userMessage }]
  };
} else {
  throw new Error(`Provider desconhecido: ${providerName}`);
}

return [{ json: { llmUrl, requestHeaders, requestBody, provider, ingestion_id: data.ingestion_id, shared_context: data.shared_context } }];

const llmResponse = $json;
const prevData = $('Montar LLM Request').item.json;
let rawContent = '';
if (llmResponse.content && llmResponse.content[0] && llmResponse.content[0].text) {
  rawContent = llmResponse.content[0].text;
} else if (llmResponse.choices && llmResponse.choices[0] && llmResponse.choices[0].message) {
  rawContent = llmResponse.choices[0].message.content;
} else {
  rawContent = JSON.stringify(llmResponse);
}
let parsed = {};
try {
  parsed = JSON.parse(rawContent);
} catch (e) {
  const match = rawContent.match(/\{[\s\S]*\}/);
  if (match) { try { parsed = JSON.parse(match[0]); } catch (e2) { parsed = {}; } }
}
const scores = parsed.scores || {};
const avgScore = Object.keys(scores).length > 0
  ? Math.round(Object.values(scores).reduce((a, b) => a + Number(b), 0) / Object.keys(scores).length)
  : 0;
const personaOutput = {
  schema_version: 'PersonaOutput-v2',
  score: avgScore,
  findings: parsed.issues || [],
  recommendations: parsed.recommendations || parsed.questions || [],
  ocg_contributions: parsed.ocg_contributions && typeof parsed.ocg_contributions === 'object' ? { individual: parsed.ocg_contributions.individual || scores || {}, global_delta: parsed.ocg_contributions.global_delta || {} } : { individual: scores || {}, global_delta: {} },
  blocking_reason: null,
  persona_tag: 'GP',
  persona_name: 'Gerente de Projetos',
  ingestion_id: prevData.ingestion_id,
  scores,
  avg_score: avgScore,
  approved: parsed.approved || false,
  blocking: false,
  issues: parsed.issues || [],
  questions: parsed.questions || [],
  justification: parsed.justification || '',
  metadata: parsed.metadata || {}
};
return [{ json: { personaOutput, ingestion_id: prevData.ingestion_id } }];
